"""jsonschema_specifications — stub providing JSON Schema meta-schema registry."""

import referencing
import referencing.jsonschema
from rpds import HashTrieMap

__version__ = "2024.10.1"

# JSON Schema meta-schemas (minimal stubs for validation)
_METASCHEMAS = {
    "http://json-schema.org/draft-03/schema#": {
        "$schema": "http://json-schema.org/draft-03/schema#",
        "id": "http://json-schema.org/draft-03/schema#",
        "type": "object",
    },
    "http://json-schema.org/draft-04/schema#": {
        "$schema": "http://json-schema.org/draft-04/schema#",
        "id": "http://json-schema.org/draft-04/schema#",
        "type": "object",
    },
    "http://json-schema.org/draft-06/schema#": {
        "$schema": "http://json-schema.org/draft-06/schema#",
        "$id": "http://json-schema.org/draft-06/schema#",
        "type": "object",
    },
    "http://json-schema.org/draft-07/schema#": {
        "$schema": "http://json-schema.org/draft-07/schema#",
        "$id": "http://json-schema.org/draft-07/schema#",
        "type": "object",
    },
    "https://json-schema.org/draft/2019-09/schema": {
        "$schema": "https://json-schema.org/draft/2019-09/schema",
        "$id": "https://json-schema.org/draft/2019-09/schema",
        "type": ["object", "boolean"],
    },
    "https://json-schema.org/draft/2020-12/schema": {
        "$schema": "https://json-schema.org/draft/2020-12/schema",
        "$id": "https://json-schema.org/draft/2020-12/schema",
        "type": ["object", "boolean"],
    },
}

def _build_registry():
    pairs = []
    for uri, schema in _METASCHEMAS.items():
        resource = referencing.Resource.from_contents(
            schema, default_specification=referencing.jsonschema.DRAFT202012
        )
        pairs.append((uri, resource))
    return referencing.Registry().with_resources(pairs)

try:
    REGISTRY = _build_registry()
except Exception:
    # Fallback: empty registry — jsonschema will still work for basic validation
    REGISTRY = referencing.Registry()
